本文主要学习陈小玉老师的《算法训练营》一书
queue容器queue是一个先进先出的容器，比如我们排队，先排的往往被先服务，后排的被后服务。
stack和queue的不同
stack：先进后出    queue：先进先出
stack取栈顶：top( )   queue取队头： front( )
无论是取栈顶还是队头，他们都还在stack或者queue容器中

头文件include&lt;queue&gt;



例题POJ1915
问题重述
已知棋盘棋子的起点和终点，棋子只能和中国象棋’马’走日字，求起点移动到终点的最少移动次数。

输入
输入从单行上的n个用例开始。  接下来是n个用例。 每个用例由三行包含整数的行组成。 第一行指定了棋盘一侧的长度l (4 &lt;= l &lt;= 300)。 整个板的大小为l * l，第二行和第三行包含一对整数{0，… l - 1} *{0,… ， l-1}表示骑士在棋盘上的起始和结束位置。 整数之间用一个空格隔开。 你可以假设这些位置都是在这种情况下棋盘上的有效位置。 

输出
对于每个输入场景，你必须计算从起点移动到终点所需的最小骑士移动量。 如果起点和终点相等，距离为零。 这个距离必须写在单行上。 

案例
分析典型的bfs（广度优先搜索），先将起点放入队列，然后循环判队列是否为空，如果为空，说明已经到达终点，如果不空，取出队头，八方向搜索，搜索分成两种情况，1.新的坐标点在终点，那用此时的步数+1即可 2.新坐标符合范围且未被搜索，加入队列中，并标记已搜索。
代码#include&lt;iostream&gt; &#x2F;&#x2F;io 
#include&lt;queue&gt; &#x2F;&#x2F;队列的使用 
#include&lt;string.h&gt; &#x2F;&#x2F;memset的使用
using namespace std;
#define MAX 302 

&#x2F;&#x2F;坐标的结构体 
struct point&#123;
	int x,y;
	int step;
&#125;;

&#x2F;&#x2F;八个方向的偏移量 
int dx[8] &#x3D; &#123;-2,-1,1,2,2,1,-1,-2&#125;;
int dy[8] &#x3D; &#123;1,2,2,1,-1,-2,-2,-1&#125;;

bool vis[MAX][MAX];&#x2F;&#x2F;记录是否走过 

int bfs()
&#123;
	&#x2F;&#x2F;定义和初始化 
	int L;
	int sx,sy,ex,ey;&#x2F;&#x2F;定义起点和终点
	int tx,ty;&#x2F;&#x2F;八方向搜索后的点 
	int x,y,step;&#x2F;&#x2F;取出结构体


	memset(vis,false,sizeof(vis)); 
	queue&lt;point&gt;que;

	&#x2F;&#x2F;输入 
	cin &gt;&gt; L;
	cin &gt;&gt; sx &gt;&gt; sy;
	cin &gt;&gt; ex &gt;&gt; ey;

	if(ex &#x3D;&#x3D; sx &amp;&amp; ey &#x3D;&#x3D; sy)&#x2F;&#x2F;一开始起点终点相同
		return 0; 

	point start, node;&#x2F;&#x2F;start:起点的结构体,node:过程的结构体 

	&#x2F;&#x2F;起点赋值到结构体，python一般使用列表
	start.x &#x3D; sx;
	start.y &#x3D; sy;
	start.step &#x3D; 0;

	&#x2F;&#x2F;入队 
	que.push(start);

	while(!que.empty())
	&#123;
		&#x2F;&#x2F;取出que里的结构体，并弹出 
		start &#x3D; que.front(),que.pop();	
		x &#x3D; start.x;
		y &#x3D; start.y;
		step &#x3D; start.step;
		for(int i &#x3D; 0;i &lt;8;i++)&#x2F;&#x2F;八方向搜索 
		&#123;
			tx &#x3D; x +dx[i];
			ty &#x3D; y +dy[i];
			if(tx &#x3D;&#x3D; ex &amp;&amp; ty &#x3D;&#x3D; ey)
				return step+1;
			if(tx &gt;&#x3D; 0 &amp;&amp; tx &lt; L &amp;&amp; ty &gt;&#x3D; 0 &amp;&amp; ty &lt; L &amp;&amp; !vis[tx][ty])
			&#123;
				node.x &#x3D; tx;
				node.y &#x3D; ty;
				node.step &#x3D; step+1;
				que.push(node);
				vis[tx][ty] &#x3D; true;
			&#125;
		&#125;


	&#125;
	return step;		
&#125;

int main()
&#123;	
	int N,res;
	cin &gt;&gt; N;
	while(N--) 
	&#123;
		res &#x3D; bfs();
		cout &lt;&lt; res &lt;&lt; endl;
	&#125;
	return 0;
&#125; 



程序涉及的函数





提示
.empty( )：容器是否为空.push( )：入队列.pop( )：出队列.front( )：取队头









特别注意

stack和queue都没有clear函数，需要自己手动实现。用while、empty、pop组合不断清空即可。
stack和queue中pop函数的返回值是void，而不是pop出来的元素，所以不能赋值给变量，正确做法：先取栈顶或队头，后pop



如有错误，敬请指正，欢迎交流，谢谢♪(･ω･)ﾉ

本文主要学习陈小玉老师的《算法训练营》一书
stack容器stack是一个先进后出的容器，比如我们拿一个玻璃瓶装糖果，先下去的糖果往往最后才能拿出来。
stack和vector的不同
vector能对任意位置插入删除，stack只能对栈顶进行操作
vector支持随机访问，stack只能访问栈顶
vector尾插尾删都在push或者pop的基础上加_back，但stack对栈顶的操作只要push入栈或者pop出栈

头文件include&lt;stack&gt;



例题POJ1028
问题重述某web默认初始URL为http://www.acm.org/，通过两个栈：前向栈和后向栈进行对页面的前后切换。有以下四种命令：

BACK：当前页到前向栈栈顶，后向栈栈顶变成当前页。如果后向栈为空，忽视该指令

FORWORD：当前页到后向栈栈顶，前向栈栈顶变成当前页。如果前向栈为空，忽视该指令

VISIT：将当前页推到后向栈顶，使URL成为新的页面，并清空前向栈

QUIT：退出浏览器


输入输入是一系列命令。 命令关键字BACK、FORWARD、VISIT、QUIT均为大写。 url没有空格，最多70个字符。 您可以假设，任何时候，任何问题实例在每个堆栈中都不超过100个元素。 输入的结束由QUIT命令指示。 
输出对于除QUIT以外的其他命令，如果不忽略该命令，则在命令执行后打印当前页面的URL。 
否则,打印“Ignored”。 每个命令的输出都应该打印在单独的一行上。 QUIT命令没有输出。 
案例
分析默认网址和两个栈定义完后，分别写函数完成对应操作，在操作一些指令时，注意先判空。而且像visit指令实际上用了空格和网址分开，那么我们实际上可以先读取一个字符串判断是什么指令，然后针对不同指令进行不同处理。
代码#include&lt;iostream&gt; &#x2F;&#x2F;io 
#include&lt;stack&gt; &#x2F;&#x2F;栈的使用 
#include&lt;string&gt; &#x2F;&#x2F;string类型的使用 
using namespace std;

&#x2F;&#x2F;定义栈 
stack&lt;string&gt;front;&#x2F;&#x2F;前向栈 
stack&lt;string&gt;back;&#x2F;&#x2F;后向栈 
string url &#x3D; &quot;http:&#x2F;&#x2F;www.acm.org&#x2F;&quot; ;&#x2F;&#x2F;当前页网址
string s;&#x2F;&#x2F;指令 
int main()
&#123;
	while(cin &gt;&gt; s) 
	&#123;	 
		if(s &#x3D;&#x3D; &quot;BACK&quot;)
		&#123;
			if(!back.empty())&#x2F;&#x2F;还能后退 
			&#123;
				front.push(url);
				url &#x3D; back.top();&#x2F;&#x2F;取栈顶 
				back.pop();
				cout &lt;&lt; url &lt;&lt; endl;
			&#125; 
			else
				cout &lt;&lt; &quot;Ignored&quot; &lt;&lt; endl; 

		&#125;
		else if(s &#x3D;&#x3D; &quot;FORWARD&quot;)
		&#123;
			if(!front.empty()) &#x2F;&#x2F;还能前进
			&#123; 
				back.push(url);
				url &#x3D; front.top();&#x2F;&#x2F;取栈顶 
				front.pop();
				cout &lt;&lt; url &lt;&lt; endl;
			&#125; 
			else
				cout &lt;&lt; &quot;Ignored&quot; &lt;&lt; endl; 
		&#125; 
		else if(s &#x3D;&#x3D; &quot;VISIT&quot;)
		&#123;
			back.push(url);
			cin &gt;&gt; url;&#x2F;&#x2F;当前页面
			while(!front.empty())&#x2F;&#x2F;前向页面不为空 
			&#123;
				front.pop();&#x2F;&#x2F;不断弹出，直到清空 
			&#125;
			cout &lt;&lt; url &lt;&lt; endl;
		&#125;
		else if(s &#x3D;&#x3D; &quot;QUIT&quot;)
		&#123;
			return 0;&#x2F;&#x2F;退出 
		&#125; 
	&#125;
&#125;



程序涉及的函数





提示
.empty( )：容器是否为空.push( )：入栈.pop( )：出栈.top( )：取栈顶









特别注意

stack和queue都没有clear函数，需要自己手动实现。用while、empty、pop组合不断清空即可。
stack中pop函数的返回值是void，而不是pop出来的元素，所以不能赋值给变量，正确做法：先取栈顶，后pop



如有错误，敬请指正，欢迎交流，谢谢♪(･ω･)ﾉ

本文主要学习陈小玉老师的《算法训练营》一书
vector容器vector：是一个封装动态数组的顺序容器
头文件#include&lt;vector&gt;



创建一个空的vector，数据类型为int，数组名为a
vector&lt;int&gt;a;



如果要指定元素个数：
vector&lt;int&gt;a(元素个数);



如果要指定数组中每个元素的初值：
vector&lt;int&gt;a(元素个数,元素初值);

总结：vector&lt;数据类型&gt;数组名(元素个数，元素初值)
b数组复制a数组，首先b和a需要同类型，所以前面声明一个数组b，然后**(被复制的对象)**：
vector&lt;int&gt;b(a)

注意：a和b的地址空间并不相同，也就是更改b并不影响a原来的值
复制区间[a.begin()+3,a.end()-3),即第四个元素到倒数第四个元素：
vector&lt;int&gt;b(a.begin()+3,a.end()-3)



增加尾插指定元素：
a.push_back(6)



指定元素头插(位置,元素)让10成为下标为1的元素：
a.insert(a.begin()+1,10)



指定元素多次头插(位置,个数,元素)：
a.insert(a.begin()+1,5,10)



指定元素头插区间(位置,区间头,区间尾)：
a.insert(a.begin()+1,b.begin(),b.begin()+3)



删除尾删：
a.pop_back()



删除指定位置的元素：
a.erase(a.begin())



删除区间(区间头,区间尾)：
a.erase(a.begin()+1,a.begin()+3)



清空向量：
a.clear()



遍历下标遍历：
for(int i &#x3D; 0;i &lt; a.size();i++)
	cout &lt;&lt; a[i] &lt;&lt; &quot; &quot;;

迭代器遍历：
for(vector&lt;int&gt;::iterator it &#x3D; a.begin();it &lt; a.end();it++) &#x2F;&#x2F;定义与容器同种类型的迭代器it
	cout &lt;&lt; *it &lt;&lt; endl;

迭代器it的使用类似指针,所以取值为：*it 
改变大小a.resize(n);

如果：

resize个数 &gt; 当前向量大小，则填充

resize个数 &lt; 当前向量大小，则从最后开始舍弃


例题HDU3527
问题重述X国有两份名单，一份是之前X-&gt;Y的间谍名单，一份是Y-&gt;X的间谍名单，两份名单存在同一个名字的为双重间谍。现在边境上有一群人将进入X国，但X国只让双重间谍和普通人进来，需要列出需要抓捕的间谍名单。
输入有几个测试用例。每个测试用例包含四个部分，第一部分包含3个正整数A、B、C，
A是进入边境的人数。 B是Y-&gt;X的间谍人数，C是之前X-&gt;Y的间谍人数。  
第二部分包含A个字符串，进入边境的名单。  
第二部分包含B个字符串，Y-&gt;X的间谍名单。  
第二部分包含C字符串，之前X-&gt;Y的间谍名单。  
在每个测试用例之后都有一个空行。  
在一个列表中不会出现重复的名字，如果重复的名字出现在两个列表中，他们意味着同一个人。
输出按列表B的顺序，依次输出间谍名单，如果没有，则输出“No enemy spy”
分析其实只要找到在Y-&gt;X中，但不在X-&gt;Y就是Y国的间谍，而我们还需要判断间谍有没有进入边境
代码#include&lt;iostream&gt; &#x2F;&#x2F;io 
#include&lt;vector&gt; &#x2F;&#x2F;动态数组的使用 
#include&lt;string&gt; &#x2F;&#x2F;string类型的使用 
#include&lt;algorithm&gt; &#x2F;&#x2F;find函数 
using namespace std;

&#x2F;&#x2F;定义动态数组 
vector&lt;string&gt;A;&#x2F;&#x2F;边界的人 
vector&lt;string&gt;B;&#x2F;&#x2F;Y-&gt;X 
vector&lt;string&gt;C;&#x2F;&#x2F;X-&gt;Y 
vector&lt;string&gt;res;&#x2F;&#x2F;最后结果 

int main()
&#123;
	&#x2F;&#x2F;定义输入的变量 
	int a,b,c; 
	string s;
	while(cin &gt;&gt; a &gt;&gt; b &gt;&gt; c)
	&#123;
		&#x2F;&#x2F;由于涉及多次输入输出，所以应该先清空动态数组
		A.clear(),B.clear(),C.clear(),res.clear();

		&#x2F;&#x2F;将各个容器对应的字符串装好 
		for(int i &#x3D; 0;i &lt; a;i++)
		&#123; 
			cin &gt;&gt; s;
			A.push_back(s); 
		&#125; 

		for(int i &#x3D; 0;i &lt; b;i++)
		&#123; 
			cin &gt;&gt; s;
			B.push_back(s); 
		&#125;

		for(int i &#x3D; 0;i &lt; c;i++)
		&#123;
			cin &gt;&gt; s;
			C.push_back(s);
		&#125;

		for(int i &#x3D; 0;i &lt; b;i++)&#x2F;&#x2F;遍历Y-&gt;X
		&#123;
			if(find(A.begin(),A.end(),B[i])!&#x3D; A.end())&#x2F;&#x2F;迭代器未到最后，即在边界找到了Y-&gt;X的间谍
			&#123;
				if(find(C.begin(),C.end(),B[i])&#x3D;&#x3D; C.end())&#x2F;&#x2F;迭代器到最后，即X-&gt;Y的名单没有，即不是双面间谍	
		 			res.push_back(B[i]);&#x2F;&#x2F;将间谍加入结果 
 			&#125; 
		&#125;

		if(res.size() &#x3D;&#x3D; 0)&#x2F;&#x2F;如果结果为空，则无间谍
			cout &lt;&lt; &quot;No enemy spy&quot; &lt;&lt; endl ;
		else
		&#123; 
			for(int i &#x3D; 0;i &lt; res.size();i++) 
			&#123;
				cout &lt;&lt; res[i];
				if(i !&#x3D; res.size()-1)&#x2F;&#x2F;防止最后一个字符串有空格 
					cout &lt;&lt; &quot; &quot;;
			&#125;
			cout &lt;&lt; endl;
		&#125; 
	&#125;
	return 0; 
&#125;



程序涉及的函数





提示
find(begin,end,element)：从begin找到end，看是否存在element,如果不存在返回end.size()：容器内的元素个数.clear() ：清空.push_back()：vector插入.begin()：指向容器第一个元素的指针.end() ：指向容器最后一个元素的下个位置的指针


如有错误，敬请指正，欢迎交流，谢谢♪(･ω･)ﾉ
